74: public class PendingCheckpoint implements Checkpoint {
75: 
76:     /** Result of the {@link PendingCheckpoint#acknowledgedTasks} method. */
77:     public enum TaskAcknowledgeResult {
78:         SUCCESS, // successful acknowledge of the task
79:         DUPLICATE, // acknowledge message is a duplicate
80:         UNKNOWN, // unknown task acknowledged
81:         DISCARDED // pending checkpoint has been discarded
82:     }
83: 
84:     // ------------------------------------------------------------------------
85: 
86:     /** The PendingCheckpoint logs to the same logger as the CheckpointCoordinator. */
87:     private static final Logger LOG = LoggerFactory.getLogger(CheckpointCoordinator.class);
