109:     /** Set of acknowledged tasks. */
110:     private final Set<ExecutionAttemptID> acknowledgedTasks;
111: 
112:     /** The checkpoint properties. */
113:     private final CheckpointProperties props;
114: 
115:     /**
116:      * The promise to fulfill once the checkpoint has been completed. Note that it will be completed
117:      * only after the checkpoint is successfully added to CompletedCheckpointStore.
118:      */
119:     private final CompletableFuture<CompletedCheckpoint> onCompletionPromise;
120: 
121:     @Nullable private final PendingCheckpointStats pendingCheckpointStats;
122: 
123:     private final CompletableFuture<Void> masterTriggerCompletionPromise;
124: 
125:     /** Target storage location to persist the checkpoint metadata to. */
126:     @Nullable private CheckpointStorageLocation targetLocation;
127: 
128:     private int numAcknowledgedTasks;
129: 
130:     private boolean disposed;
