140:     public PendingCheckpoint(
141:             JobID jobId,
142:             long checkpointId,
143:             long checkpointTimestamp,
144:             CheckpointPlan checkpointPlan,
145:             Collection<OperatorID> operatorCoordinatorsToConfirm,
146:             Collection<String> masterStateIdentifiers,
147:             CheckpointProperties props,
148:             CompletableFuture<CompletedCheckpoint> onCompletionPromise,
149:             @Nullable PendingCheckpointStats pendingCheckpointStats,
150:             CompletableFuture<Void> masterTriggerCompletionPromise) {
151:         checkArgument(
152:                 checkpointPlan.getTasksToWaitFor().size() > 0,
153:                 "Checkpoint needs at least one vertex that commits the checkpoint");
154: 
155:         this.jobId = checkNotNull(jobId);
156:         this.checkpointId = checkpointId;
157:         this.checkpointTimestamp = checkpointTimestamp;
158:         this.checkpointPlan = checkNotNull(checkpointPlan);
159: 
160:         this.notYetAcknowledgedTasks =
161:                 CollectionUtil.newHashMapWithExpectedSize(
162:                         checkpointPlan.getTasksToWaitFor().size());
163:         for (Execution execution : checkpointPlan.getTasksToWaitFor()) {
164:             notYetAcknowledgedTasks.put(execution.getAttemptId(), execution.getVertex());
165:         }
166: 
167:         this.props = checkNotNull(props);
168: 
169:         this.operatorStates = new HashMap<>();
170:         this.masterStates = new ArrayList<>(masterStateIdentifiers.size());
171:         this.notYetAcknowledgedMasterStates =
172:                 masterStateIdentifiers.isEmpty()
173:                         ? Collections.emptySet()
174:                         : new HashSet<>(masterStateIdentifiers);
175:         this.notYetAcknowledgedOperatorCoordinators =
176:                 operatorCoordinatorsToConfirm.isEmpty()
177:                         ? Collections.emptySet()
178:                         : new HashSet<>(operatorCoordinatorsToConfirm);
179:         this.acknowledgedTasks =
180:                 CollectionUtil.newHashSetWithExpectedSize(
181:                         checkpointPlan.getTasksToWaitFor().size());
182:         this.onCompletionPromise = checkNotNull(onCompletionPromise);
183:         this.pendingCheckpointStats = pendingCheckpointStats;
184:         this.masterTriggerCompletionPromise = checkNotNull(masterTriggerCompletionPromise);
185:     }
