788:     private void triggerCheckpointRequest(
789:             CheckpointTriggerRequest request, long timestamp, PendingCheckpoint checkpoint) {
790:         if (checkpoint.isDisposed()) {
791:             onTriggerFailure(
792:                     checkpoint,
793:                     new CheckpointException(
794:                             CheckpointFailureReason.TRIGGER_CHECKPOINT_FAILURE,
795:                             checkpoint.getFailureCause()));
796:         } else {
797:             triggerTasks(request, timestamp, checkpoint)
798:                     .exceptionally(
799:                             failure -> {
800:                                 try (MdcUtils.MdcCloseable ignored =
801:                                         MdcUtils.withContext(MdcUtils.asContextData(job))) {
802:                                     LOG.info(
803:                                             "Triggering Checkpoint {} for job {} failed due to {}",
804:                                             checkpoint.getCheckpointID(),
805:                                             job,
806:                                             failure);
807:                                     final CheckpointException cause;
808:                                     if (failure instanceof CheckpointException) {
809:                                         cause = (CheckpointException) failure;
810:                                     } else {
811:                                         cause =
812:                                                 new CheckpointException(
813:                                                         CheckpointFailureReason
814:                                                                 .TRIGGER_CHECKPOINT_FAILURE,
815:                                                         failure);
816:                                     }
817:                                     timer.execute(
818:                                             () -> {
819:                                                 synchronized (lock) {
820:                                                     abortPendingCheckpoint(checkpoint, cause);
821:                                                 }
822:                                             });
823:                                     return null;
824:                                 }
825:                             });
826: 
827:             // It is possible that the tasks has finished
828:             // checkpointing at this point.
829:             // So we need to complete this pending checkpoint.
830:             if (maybeCompleteCheckpoint(checkpoint)) {
831:                 onTriggerSuccess();
832:             }
833:         }
834:     }
