47: /**
48:  * The {@link CheckpointBarrierTracker} keeps track of what checkpoint barriers have been received
49:  * from which input channels. Once it has observed all checkpoint barriers for a checkpoint ID, it
50:  * notifies its listener of a completed checkpoint.
51:  *
52:  * <p>Unlike the {@link SingleCheckpointBarrierHandler}, the BarrierTracker does not block the input
53:  * channels that have sent barriers, so it cannot be used to gain "exactly-once" processing
54:  * guarantees. It can, however, be used to gain "at least once" processing guarantees.
55:  *
56:  * <p>NOTE: This implementation strictly assumes that newer checkpoints have higher checkpoint IDs.
57:  */
58: @Internal
59: public class CheckpointBarrierTracker extends CheckpointBarrierHandler {
60: 
61:     private static final Logger LOG = LoggerFactory.getLogger(CheckpointBarrierTracker.class);
62: 
63:     /**
64:      * The tracker tracks a maximum number of checkpoints, for which some, but not all barriers have
65:      * yet arrived.
66:      */
67:     private static final int MAX_CHECKPOINTS_TO_TRACK = 50;
68: 
69:     // ------------------------------------------------------------------------
70: 
71:     /** The number of open channels. */
72:     private int numOpenChannels;
73: 
74:     /**
75:      * All checkpoints for which some (but not all) barriers have been received, and that are not
76:      * yet known to be subsumed by newer checkpoints.
77:      */
78:     private final ArrayDeque<CheckpointBarrierCount> pendingCheckpoints;
79: 
80:     /** The highest checkpoint ID encountered so far. */
81:     private long latestPendingCheckpointID = -1;
82: 
83:     public CheckpointBarrierTracker(
84:             int totalNumberOfInputChannels,
85:             CheckpointableTask toNotifyOnCheckpoint,
86:             Clock clock,
87:             boolean enableCheckpointAfterTasksFinished) {
88:         super(toNotifyOnCheckpoint, clock, enableCheckpointAfterTasksFinished);
89:         this.numOpenChannels = totalNumberOfInputChannels;
90:         this.pendingCheckpoints = new ArrayDeque<>();
91:     }
