237:     protected void markCheckpointAlignedAndTransformState(
238:             InputChannelInfo alignedChannel,
239:             CheckpointBarrier barrier,
240:             FunctionWithException<BarrierHandlerState, BarrierHandlerState, Exception>
241:                     stateTransformer)
242:             throws IOException {
243: 
244:         alignedChannels.add(alignedChannel);
245:         if (alignedChannels.size() == 1) {
246:             if (targetChannelCount == 1) {
247:                 markAlignmentStartAndEnd(barrier.getId(), barrier.getTimestamp());
248:             } else {
249:                 markAlignmentStart(barrier.getId(), barrier.getTimestamp());
250:             }
251:         }
252: 
253:         // we must mark alignment end before calling currentState.barrierReceived which might
254:         // trigger a checkpoint with unfinished future for alignment duration
255:         if (alignedChannels.size() == targetChannelCount) {
256:             if (targetChannelCount > 1) {
257:                 markAlignmentEnd();
258:             }
259:         }
260: 
261:         try {
262:             currentState = stateTransformer.apply(currentState);
263:         } catch (CheckpointException e) {
264:             abortInternal(currentCheckpointId, e);
265:         } catch (Exception e) {
266:             ExceptionUtils.rethrowIOException(e);
